  ('aboriginal-a5729396-moex-00364', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列何種事項，不適用行政程序法之程序規定？', '["警察局對交通違規裁罰之行為", "衛生局命業者停止販售並封存過期食品之行為", "考試院有關考選命題及評分之行為", "市政府勞工局發放失業救助金之行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00365', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列何者係屬信賴保護之類型？', '["經廢止之法規有重大明顯違反上位規範者", "當事人客觀上具體表現其因信賴而生之實體法之利益，因法規廢止而受損", "當事人之行為不符合誠信原則", "當事人之行為純屬願望或期待"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00366', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '行政機關在若干行為領域中，享有所謂「判斷餘地」。有關判斷餘地之說明，下列何者正確？', '["判斷餘地，意指此一領域之決定，絕對不受法院審查", "判斷餘地，因必然涉及人民重大基本權，必須有法律之明文依據方予以承認", "涉及專業判斷而由具有一定獨立地位委員會所作成之決定，在我國法律中比較容易被承認機關有判斷餘地", "判斷餘地，表示機關就特定事務，依法有採取特定措施處理的義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00367', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '行政機關執行職務，應當積極主動，對當事人之主張應有全面的關照，無待於相對人之請求。這樣的原則， 在行政程序法中被稱為：', '["比例原則", "信賴保護原則", "有利不利一律注意原則", "明確性原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00368', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '有關警察機關委託民間業者執行違規停車之車輛拖吊業務，下列敘述何者錯誤？', '["拖吊業者得獨立判斷車輛是否違規，以及是否有拖吊之必要", "拖吊業者從事拖吊業務造成車輛損害，警察機關應負損害賠償責任", "對於因拖吊過程造成車輛之損害，以金錢賠償為原則，回復原狀為例外", "警察機關得與民間業者以契約協定，由其負擔因執行拖吊業務對車主產生之損害"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00369', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '有關公務員國家賠償責任之敘述，下列何者錯誤？', '["公務員因執行職務所生之國家賠償責任以公務員有故意或過失為前提", "從事審判事務職務之公務員，因誤判而造成人民之損害，即應負國家賠償責任", "因公務員之重大過失造成之國家賠償責任，賠償義務機關對該公務員有求償權", "人民之非財產上之權利，因公務員之違法行為受到損害者，亦得請求賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00370', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '國家賠償請求權人向賠償義務機關請求賠償，自開始協商之日起逾幾日協議不成立，請求權人得提起損害 賠償之訴？', '["15日", "30日", "60日", "90日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00371', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '依司法院釋字第440號解釋，主管機關對都市計畫道路用地，在依法徵收或價購前，埋設地下設施物，妨 礙土地權利人對其權利之行使，致生損失，應負何種責任？', '["國家賠償責任", "損失補償責任", "民事賠償責任", "刑事責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00372', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '依憲法學理，下列何者並非總統制的特徵？', '["總統身兼國家元首與行政首長", "總統不對國會負責", "總統得解散國會", "總統由人民直接選舉產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00373', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '關於利害關係人提起訴願之法定要件，下列何者錯誤？', '["利害關係人提起訴願，自知悉行政處分時起算訴願期間", "縱尚未知悉，利害關係人必須在行政處分達到或公告期滿之3年內，提起訴願", "利害關係人因為未受行政處分之送達，因此提起訴願之期間不受任何限制", "利害關係人若因天災遲誤法定訴願期間，得於原因消滅後10日內，申請回復原狀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
